#include <stdio.h>
#include <stdlib.h>

#define MAX 1000

int heap[MAX];
int heap_size = 0;

// Function to swap two elements
void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

// Function to insert a value into the heap
void insert(int value) {
    heap[heap_size] = value;
    int cur_index = heap_size;
    heap_size++;

    // Heapify up
    while (cur_index != 0) {
        int parent_index = (cur_index - 1) / 2;
        if (heap[parent_index] > heap[cur_index]) {
            swap(&heap[parent_index], &heap[cur_index]);
        }
        cur_index = parent_index;
    }
}

// Function to heapify down from a given index
void heapify(int index) {
    int smallest = index;
    int left_child = 2 * index + 1;
    int right_child = 2 * index + 2;

    if (left_child < heap_size && heap[left_child] < heap[smallest]) {
        smallest = left_child;
    }
    if (right_child < heap_size && heap[right_child] < heap[smallest]) {
        smallest = right_child;
    }

    if (smallest != index) {
        swap(&heap[index], &heap[smallest]);
        heapify(smallest);
    }
}

// Function to delete the root of the heap (min element)
void delete_from_heap() {
    if (heap_size == 0) return;

    int index = 0;
    swap(&heap[index], &heap[heap_size - 1]);
    heap_size--;
    heapify(index);
}

// Function to print the heap
void print_heap() {
    for (int i = 0; i < heap_size; i++) {
        printf("%d ", heap[i]);
    }
    printf("\n");
}

int main() {
    int n;
    scanf("%d", &n);

    for (int i = 0; i < n; i++) {
        char command[10];
        scanf("%s", command);

        if (strcmp(command, "insert") == 0) {
            int value;
            scanf("%d", &value);
            insert(value);
        } 
        else if (strcmp(command, "delete") == 0) {
            delete_from_heap();
        } 
        else if (strcmp(command, "print") == 0) {
            print_heap();
        }
    }

    return 0;
}

