import java.util.*;

class Heap {
    List<Integer> v = new ArrayList<>();

    // Insert a value into the heap
    void insert(int value) {
        v.add(value);
        int curIndex = v.size() - 1;

        while (curIndex != 0) {
            int parentIndex = (curIndex - 1) / 2;
            if (v.get(parentIndex) > v.get(curIndex)) {
                Collections.swap(v, parentIndex, curIndex);
            }
            curIndex = parentIndex;
        }
    }

    // Heapify down (for min-heap)
    void heapify(int index) {
        int smallest = index;
        int leftChild = 2 * index + 1;
        int rightChild = 2 * index + 2;

        if (leftChild < v.size() && v.get(leftChild) < v.get(smallest)) {
            smallest = leftChild;
        }
        if (rightChild < v.size() && v.get(rightChild) < v.get(smallest)) {
            smallest = rightChild;
        }

        if (smallest != index) {
            Collections.swap(v, index, smallest);
            heapify(smallest);
        }
    }

    // Delete the root element (min element)
    void deleteFromHeap() {
        if (v.size() == 0) return;

        int index = 0;
        Collections.swap(v, index, v.size() - 1);
        v.remove(v.size() - 1);
        if (v.size() > 0) heapify(index);
    }

    // Print all elements
    void printHeap() {
        for (int num : v) {
            System.out.print(num + " ");
        }
        System.out.println();
    }
}

class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        Heap h1 = new Heap();

        int n = sc.nextInt(); // number of commands
        for (int i = 0; i < n; i++) {
            String command = sc.next();

            if (command.equals("insert")) {
                int value = sc.nextInt();
                h1.insert(value);
            } else if (command.equals("delete")) {
                h1.deleteFromHeap();
            } else if (command.equals("print")) {
                h1.printHeap();
            }
        }

        sc.close();
    }
}

