class Heap {
    constructor() {
        this.v = [];
    }

    insert(value) {
        this.v.push(value);
        let curIndex = this.v.length - 1;
        while (curIndex !== 0) {
            let parentIndex = Math.floor((curIndex - 1) / 2);
            if (this.v[parentIndex] > this.v[curIndex]) {
                [this.v[parentIndex], this.v[curIndex]] = [this.v[curIndex], this.v[parentIndex]];
            }
            curIndex = parentIndex;
        }
    }

    heapify(index) {
        let leftChild = 2 * index + 1;
        let rightChild = 2 * index + 2;

        if (leftChild < this.v.length && this.v[leftChild] < this.v[index]) {
            [this.v[index], this.v[leftChild]] = [this.v[leftChild], this.v[index]];
            this.heapify(leftChild);
        }

        if (rightChild < this.v.length && this.v[rightChild] < this.v[index]) {
            [this.v[index], this.v[rightChild]] = [this.v[rightChild], this.v[index]];
            this.heapify(rightChild);
        }
    }

    deleteFromHeap() {
        let index = 0;
        [this.v[index], this.v[this.v.length - 1]] = [this.v[this.v.length - 1], this.v[index]];
        this.v.pop();
        this.heapify(index);
    }
}

